#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int r1, k1, r2, k2;
    cin >> r1 >> k1 >> r2 >> k2;

    long long ans = LLONG_MAX;

    // We can think of the spider web in terms of coordinates.
    // Convert to 0-based ray indices:
    int a = r1 - 1, b = r2 - 1;

    // The distance between two rays i and j in the circular sense (0..5):
    auto ray_dist = [&](int i, int j) -> int {
        int d = abs(i - j);
        return min(d, 6 - d);
    };

    // The optimal path will go from (r1,k1) to some ring level h (0 <= h <= max(k1,k2))
    // then along the ring to align with r2, then radially outward/inward to (r2,k2).

    // Equivalent formulation: we can travel radially (changing k) at cost 1 per unit,
    // and circularly (changing ray) at ring level k with cost k per step (adjacent ray step).

    // The minimal distance can be reasoned as:
    // Let d_ray = ray_dist(a, b) = number of ray steps between r1 and r2.
    // Option 1: go to ring 0 (center), then out to (r2,k2)
    long long option1 = k1 + k2; // radial only through center
    ans = min(ans, option1);

    // Option 2: go to some ring L, travel along it, then go radially
    // The optimal L is somewhere between min(k1,k2) and max(k1,k2), but we can
    // directly compute: go from k1 to L, travel d_ray * L, then from L to k2.
    // The total = |k1 - L| + |k2 - L| + d_ray * L.
    // This is minimized at L = something...
    // But we can also consider going to the outer ring and back.

    // A simpler approach: the answer is:
    // dist = min over L>=0 of |k1 - L| + |k2 - L| + d_ray * L
    // And also L can be 0 (already covered as option1).

    // We can find the best L by analyzing the piecewise linear function.
    // Let f(L) = |k1 - L| + |k2 - L| + d_ray * L.
    // For L <= min(k1,k2): f(L) = (k1 - L) + (k2 - L) + d_ray * L = k1 + k2 + (d_ray - 2)*L
    //   This is minimized at L = 0 if d_ray >= 2, or at L = min(k1,k2) if d_ray < 2.
    // For min(k1,k2) <= L <= max(k1,k2): f(L) = |k1 - k2| + (d_ray - 1)*L ??? let's be careful.
    //   WLOG k1 <= k2: then for L in [k1, k2]: f(L) = (L - k1) + (k2 - L) + d_ray * L = (k2 - k1) + d_ray * L
    //   This is increasing with L, so min at L = k1.
    // For L >= max(k1,k2): f(L) = (L - k1) + (L - k2) + d_ray * L = -(k1+k2) + (2 + d_ray)*L
    //   Increasing with L, min at L = max(k1,k2).

    // So the candidates for optimal L are: 0, min(k1,k2), max(k1,k2).
    // Also possibly some intermediate value? Let's check analytically.
    // Actually for d_ray = 0, f(L) = |k1-L|+|k2-L|, minimized at any L between k1 and k2, value = |k1-k2|.
    // For d_ray = 1: between k1 and k2, f(L) = |k1-k2| + L, minimized at L = min(k1,k2), value = |k1-k2| + min(k1,k2).
    // For d_ray >= 2: the decreasing part only at L in [0,min(k1,k2)] with slope d_ray-2 >= 0, so min at L=0.

    // But wait, we might also consider going the long way around the circle (6 - d_ray steps).
    // Actually d_ray is already the minimal ray distance.
    // However, sometimes taking more ray steps but on a smaller ring could be better?
    // The formula already accounts for d_ray minimal; using more steps would be worse since cost is proportional to L.

    int d = ray_dist(a, b);
    long long k_min = min(k1, k2);
    long long k_max = max(k1, k2);

    // L = 0
    ans = min(ans, (long long)k1 + k2);

    // L = k_min
    // f(k_min) = |k1 - k_min| + |k2 - k_min| + d * k_min
    // = (k1 - k_min) + (k2 - k_min) + d * k_min = k1 + k2 - 2*k_min + d*k_min
    // But if k1 == k_min and k2 == k_max, then k1 - k_min = 0, k2 - k_min = k_max - k_min = |k1-k2|
    // So = |k1-k2| + d * k_min
    ans = min(ans, (long long)abs(k1 - k2) + d * k_min);

    // L = k_max
    // f(k_max) = (k_max - k1) + (k_max - k2) + d * k_max = 2*k_max - (k1+k2) + d*k_max
    ans = min(ans, (long long)k_max * (2 + d) - (k1 + k2));

    // But there is another possibility: instead of using the minimal ray distance d,
    // maybe going the other way around (6-d steps) is better if L is large?
    // That's actually covered because d is already the minimal circular distance.
    // Using more steps would strictly increase cost since d_ray * L would be larger.
    // So no.

    // However, one more nuance: we might travel radially outward first, then along a ring,
    // then radially inward. The formula with L = max(k1,k2) accounts for going outward to
    // the larger ring, then along it, then inward... but if both are at same ring, that's fine.

    // Actually there is also the possibility of going radially inward to 0, then out different ray.
    // That's option1 = k1 + k2.

    // Let's also consider going to some intermediate level L that's not one of these three.
    // For d=0: the minimum is |k1-k2|, achieved at any L between k1 and k2. Our candidates:
    // f(0)=k1+k2, f(k_min)=|k1-k2|, f(k_max)=|k1-k2|. So we get the right answer.
    // For d=1: f(L)=|k1-L|+|k2-L|+L. The minimum occurs at L = min(k1,k2). Our candidates include it.
    // For d>=2: minimum at L=0 (or negative which is not allowed). So our candidates cover it.

    // But wait -- what if k1=0 or k2=0? The center station (0) is at ring 0, and it's just one point
    // (all rays meet there). Traveling to/from it costs k (radial distance). That's covered.

    // Let's test with samples.

    cout << ans << "\n";

    return 0;
}
